SELECT DISTINCT boat_name
FROM yachts
WHERE yacht_id IN (SELECT yacht_id FROM results);

SELECT boat_name
FROM yachts
WHERE length = (SELECT MAX(length) FROM yachts);

SELECT boat_name, year_built
FROM yachts
ORDER BY year_built DESC;

SELECT helm_name, crew_name, helm_experience
FROM helm_crew
WHERE helm_crew_id = 0;

SELECT boat_name
FROM yachts
ORDER BY boat_name ASC;

SELECT SUM(points) AS total_points
FROM ranks
WHERE yacht_id = 1;

SELECT AVG(helm_experience) AS avg_helm_experience
FROM helm_crew
WHERE yacht_id = 1;
